    public long round(double value) {
        switch (strategy) {
            case CEIL:
                return Math.max(1, (long) Math.ceil(value));
            case FLOOR:
                return Math.max(1, (long) Math.floor(value));
            default:
            case ROUND_HALF_UP:
                return Math.max(1, Math.round(value));
        }
